const e=JSON.parse('{"key":"v-76bc07d8","path":"/learningNote/Computer_Network/%E9%BB%91%E6%B4%9E%E8%B7%AF%E7%94%B1.html","title":"黑洞路由","lang":"zh-CN","frontmatter":{"title":"黑洞路由","category":["Computer","Network","basic"]},"headers":[],"git":{"createdTime":1692780329000,"updatedTime":1692780329000,"contributors":[{"name":"Jeacson_Snake","email":"Jeacson_Snake@outlook.com","commits":1}]},"readingTime":{"minutes":0.41,"words":122},"filePathRelative":"learningNote/Computer_Network/黑洞路由.md","localizedDate":"2023年8月23日","excerpt":"<p>黑洞路由也为一条静态路由，但与其他路由不同的是，黑洞路由的出口接口为NULL0。如果一条静态路由的出口接口为NULL0时，我们此条路由为黑洞路由。</p>\\n<p>简单的来说，若一条静态路由的网段的出口接口被指定为NULL0时，那么，去往这个网段内所有的数据报文将被直接丢弃，不进行转发。</p>\\n"}');export{e as data};
